workspace.tests/fetchData.test.mjs:
import { fetchData } from '../src/fetchData.mjs';

const assert = (c, m) => { if (!c) throw new Error(m); };

function createMockFetch(failCount) {
  let calls = 0;
  return async function mockFetch(url) {
    calls++;
    if (calls <= failCount) {
      throw new Error('Network error on attempt ' + calls);
    }
    return { url, data: 'success', attempt: calls };
  };
}

async function runTests() {
  // Test 1: succeeds on first try
  const mock1 = createMockFetch(0);
  const r1 = await fetchData(mock1, 'https://api.example.com/data');
  assert(r1.data === 'success', 'Should succeed on first try but got ' + JSON.stringify(r1));
  assert(r1.attempt === 1, 'Should have been called once but attempt is ' + r1.attempt);

  // Test 2: succeeds on second try after one failure
  const mock2 = createMockFetch(1);
  const r2 = await fetchData(mock2, 'https://api.example.com/data');
  assert(r2.data === 'success', 'Should succeed on retry');
  assert(r2.attempt === 2, 'Should have been called twice but attempt is ' + r2.attempt);

  // Test 3: succeeds on third try after two failures
  const mock3 = createMockFetch(2);
  const r3 = await fetchData(mock3, 'https://api.example.com/data');
  assert(r3.data === 'success', 'Should succeed on third try');
  assert(r3.attempt === 3, 'Should have been called three times but attempt is ' + r3.attempt);

  // Test 4: fails after 3 attempts (all fail)
  const mock4 = createMockFetch(10);
  try {
    await fetchData(mock4, 'https://api.example.com/data');
    assert(false, 'Should have thrown after 3 failed attempts');
  } catch (e) {
    assert(e.message.includes('Network error'), 'Should throw the last error: ' + e.message);
  }

  // Test 5: backoff timing - should take at least 100+200=300ms for 3 attempts
  const mock5 = createMockFetch(2);
  const start = Date.now();
  await fetchData(mock5, 'https://api.example.com/data');
  const elapsed = Date.now() - start;
  assert(elapsed >= 250, 'Should have exponential backoff of at least 300ms total but took ' + elapsed + 'ms');

  console.log('ALL TESTS PASSED');
}

runTests();
